    {name:'山せん断',F:Fstr},
    {name:'ボルト破断',F:Fbrk}
  ].sort((a,b)=>a.F-b.F);

  const dominant=failModes[0].name;
  const T_fail=failModes[0].F*Knd;
  const T_jis=T_lim/sf;           // JIS標準値（ボルト強度基準）
  const softMaterials=new Set(['aluminum','cast_iron','brass','resin']);
  const isSoft=softMaterials.has(partMatKey);
  const T_rec=isSoft?Math.min(T_jis,T_fail/sf):T_jis;
  const isMaterialLimit=isSoft&&T_fail/sf<T_jis;

  ge('res-torque').textContent=T_rec.toFixed(2);
  ge('res-range').textContent=`許容範囲 ${(T_rec*0.9).toFixed(2)} 〜 ${(T_rec*1.1).toFixed(2)} N·m`;
  ge('res-fy').textContent=`軸力 Fy: ${Fy.toFixed(1)} kN`;
  ge('res-fy').style.display='';

  // 警告
  const warnEl=ge('warning-banner');
  if(isMaterialLimit && dominant.includes('山せん断')){
    warnEl.classList.add('show');
    ge('warn-title').textContent='⚠️ 相手部材の強度により制限（標準値より低く設定）';
    ge('warn-detail').textContent=`JIS B 1083標準値（ボルト強度基準）: ${T_jis.toFixed(2)} N·m ／ 相手部材の山せん断強度を考慮して低減しています。ねじ込み深さを増やすか相手材の強化を推奨します。`;
  } else if(isMaterialLimit && dominant.includes('座面')){
    warnEl.classList.add('show');
    ge('warn-title').textContent='⚠️ 相手部材の強度により制限（標準値より低く設定）';
    ge('warn-detail').textContent=`JIS B 1083標準値（ボルト強度基準）: ${T_jis.toFixed(2)} N·m ／ 相手部材の許容面圧を考慮して推奨トルクを低減しています。`;
  } else {
    warnEl.classList.remove('show');
  }

  // 破損モードバー
  const maxT=failModes[failModes.length-1].F*Knd;
  ge('failure-list').innerHTML=failModes.map((fm,i)=>{
    const t=(fm.F*Knd).toFixed(2);
    const mg=(fm.F*Knd/T_rec).toFixed(2);
    const pct=((fm.F*Knd)/maxT*100).toFixed(1);
    const isDom=(i===0);
    const color=BAR_COLORS[Math.min(i,BAR_COLORS.length-1)];
    return `<div class="failure-item">
      <div class="fi-header">
        <div class="fi-name">${fm.name}${isDom?'<span class="fail-tag-red">制限</span>':''}</div>
        <div class="fi-value">${t} N·m / ${mg}×</div>
      </div>
      <div class="bar-track"><div class="bar-fill ${color}" style="width:${pct}%"></div></div>
    </div>`;
  }).join('');

  _lastResult={
    ts:new Date().toISOString(),
    d:d,
    grade:grK,
    part:partMatKey,
    mu:gv('mu'),
    torque:T_rec.toFixed(2),
    fy:Fy.toFixed(1),
    range:`${(T_rec*0.9).toFixed(2)}〜${(T_rec*1.1).toFixed(2)}`
  };
  autoSaveHistory();
}

function scrollToChips(){
  document.querySelector('.chips-grid').scrollIntoView({behavior:'smooth',block:'center'});
}

function getHistory(){
  try{return JSON.parse(localStorage.getItem(HISTORY_KEY)||'[]');}
  catch{return[];}
}

function autoSaveHistory(){
  if(!_lastResult)return;
  const arr=getHistory();
  if(arr.length>0){
    const last=arr[0];
    if(last.d===_lastResult.d&&last.grade===_lastResult.grade&&
       last.part===_lastResult.part&&last.mu===_lastResult.mu)return;
  }
  arr.unshift({..._lastResult,ts:new Date().toISOString()});
  localStorage.setItem(HISTORY_KEY,JSON.stringify(arr.slice(0,HISTORY_MAX)));
}

function saveHistory(){
  if(!_lastResult)return;
  const arr=getHistory();
  arr.unshift({..._lastResult,ts:new Date().toISOString()});
  localStorage.setItem(HISTORY_KEY,JSON.stringify(arr.slice(0,HISTORY_MAX)));
}

function deleteHistory(i){
  const arr=getHistory();
  arr.splice(i,1);
  localStorage.setItem(HISTORY_KEY,JSON.stringify(arr));
  renderHistory();
}

