function clearAllHistory(){
  if(!confirm('すべての履歴を削除しますか？'))return;
  localStorage.removeItem(HISTORY_KEY);
  renderHistory();
}

function renderHistory(){
  const arr=getHistory();
  const el=ge('history-list');
  if(!arr.length){
    el.innerHTML='<div class="history-empty">保存された履歴はありません。<br>計算ボタンを押すと自動保存されます。</div>';
    return;
  }
  el.innerHTML=arr.map((h,i)=>{
    const dt=new Date(h.ts);
    const fmt=`${dt.getMonth()+1}/${dt.getDate()} ${String(dt.getHours()).padStart(2,'0')}:${String(dt.getMinutes()).padStart(2,'0')}`;
    const part=CL_MAT[h.part]?CL_MAT[h.part].name:h.part;
    const mu=MU_MAP[h.mu]?MU_MAP[h.mu].label:h.mu;
    return `<div class="history-item">
      <div class="history-item-body">
        <div><span class="history-torque">${h.torque}</span><span class="history-torque-unit"> N·m</span></div>
        <div class="history-params">M${h.d} / ${h.grade} / ${part} / ${mu}</div>
        <div class="history-ts">${fmt} · ${h.range} N·m${h.fy?` · Fy ${h.fy} kN`:''}</div>
      </div>
      <button class="history-del" onclick="deleteHistory(${i})">削除</button>
    </div>`;
  }).join('');
}

function openHistory(){
  ge('history-modal').style.display='flex';
  renderHistory();
}

function closeHistory(){
  ge('history-modal').style.display='none';
}

function saveAndShare(){
  saveHistory();
  const t=ge('res-torque').textContent;
  const r=ge('res-range').textContent;
  const d=gv('diam'),g=gv('grade'),p=CL_MAT[gv('part_mat')].name,m=MU_MAP[gv('mu')].label;
  const fy=_lastResult?_lastResult.fy:'—';
  const text=`BoltSense 締め付けトルク計算（JIS B 1083）\nM${d} / ${g} / ${p} / ${m}\n推奨トルク: ${t} N·m（軸力 Fy: ${fy} kN）\n${r}`;
  if(navigator.share){
    navigator.share({title:'BoltSense 計算結果',text});
  } else if(navigator.clipboard){
    navigator.clipboard.writeText(text).then(()=>alert('クリップボードにコピーしました'));
  }
}

function openFeedback(){
  if(FEEDBACK_URL){
    window.open(FEEDBACK_URL,'_blank');
  } else {
    alert('フィードバックは takotot20002000@gmail.com までお送りください。');
  }
}

function openBoltTable(){
  const tbody=ge('bolt-table-body');
  if(!tbody.children.length){
    const gr=GRADE['8.8'];
    const {mt,mw}=MU_MAP['dry'];
    const bolts=Object.keys(BOLT).map(Number).sort((a,b)=>a-b);
    tbody.innerHTML=bolts.map(d=>{
      const b=BOLT[d];
      const Db=(b.dw+b.dh)/2;
      const K=b.p/(2*Math.PI*d)+0.577*mt*b.d2/d+mw*Db/(2*d);
      const Knd=K*d;
      const At=b.p/(2*Math.PI)+0.577*mt*b.d2;
      const dAs=Math.sqrt(4*b.As/Math.PI);
      const Fy_denom=1+3*Math.pow(3/dAs*At,2);
      const Fy=gr.Sy*b.As/Math.sqrt(Fy_denom)/1000;
      const T_rec=(Knd*Fy/1.5).toFixed(2);
      return `<tr><td>M${d}</td><td>${b.p.toFixed(2)}</td><td>${T_rec}</td><td>${b.As}</td></tr>`;
    }).join('');
  }
  ge('bolttable-modal').style.display='flex';

